module RefModule(
    input [3:0] A,
    input [3:0] B,
    input Cin,
    output [3:0] S,
    output Cout
);
    wire [3:0] obf_P, G; // Propagate and Generate
    wire [4:0] C; // Carry bits

    assign obf_P = A ^ B; // Propagate
    assign G = A & B; // Generate

    assign C[0] = Cin;
    assign C[1] = G[0] | (obf_P[0] & Cin);
    assign C[2] = G[1] | (obf_P[1] & G[0]) | (obf_P[1] & obf_P[0] & Cin);
    assign C[3] = G[2] | (obf_P[2] & G[1]) | (obf_P[2] & obf_P[1] & G[0]) | (obf_P[2] & obf_P[1] & obf_P[0] & Cin);
    assign Cout = G[3] | (obf_P[3] & G[2]) | (obf_P[3] & obf_P[2] & G[1]) | (obf_P[3] & obf_P[2] & obf_P[1] & G[0]) | (obf_P[3] & obf_P[2] & obf_P[1] & obf_P[0] & Cin);

    assign S = obf_P ^ C[3:0]; // Sum

endmodule
